What does the following program print?

```cpp
#include <iostream>

void addTen(int& x) { x += 10; }

int main() {
    int a = 5;
    const int& cr = a;
    auto copy = cr;
    addTen(copy);
    std::cout << a << ' ' << copy << '\n';
}
```

What does the following program print?

```cpp
#include <iostream>
#include <optional>

std::optional<int> half(int n) {
    if (n % 2 != 0) return std::nullopt;
    return n / 2;
}

int main() {
    std::cout << half(8).value_or(-1) << '\n';
    std::cout << half(7).value_or(-1) << '\n';
}
```
